   225	func getValueFromJSONResponse(body []byte, valueLocation string) (float64, error) {
   226		r := gjson.GetBytes(body, valueLocation)
   227		if r.Type == gjson.String {
   228			v, err := resource.ParseQuantity(r.String())
   229			if err != nil {
   230				return 0, fmt.Errorf(valueLocationWrongErrorMsg, r.String())
   231			}
   232			return v.AsApproximateFloat64(), nil
   233		}
   234		if r.Type != gjson.Number {
   235			return 0, fmt.Errorf(valueLocationWrongErrorMsg, r.Type.String())
   236		}
   237		return r.Num, nil
   238	}
