   279	func (s *metricsAPIScaler) getMetricValue(ctx context.Context) (float64, error) {
   280		// if we wish to aggregate metric from a kubernetes service then we need to query each endpoint behind the service
   281		if s.metadata.AggregateFromKubeServiceEndpoints {
   282			endpointsUrls, err := s.getEndpointsUrlsFromServiceURL(ctx, s.metadata.URL)
   283			if err != nil {
   284				return 0, fmt.Errorf("failed to get kubernetes endpoints urls from configured service URL")
   285			}
   286			if len(endpointsUrls) == 0 {
   287				return 0, fmt.Errorf("no endpoints URLs were given for the service name")
   288			}
   289			return s.aggregateMetricsFromMultipleEndpoints(ctx, endpointsUrls)
   290		}
   291		// get single/unaggregated metric
   292		metric, err := s.getMetricValueFromURL(ctx, nil)
   293		if err == nil {
   294			s.logger.V(1).Info(fmt.Sprintf("fetched single metric from metrics API url : %s. Value is %v\n", s.metadata.URL, metric))
   295		}
   296		return metric, err
   297	}
