   299	func (s *metricsAPIScaler) aggregateMetricsFromMultipleEndpoints(ctx context.Context, endpointsUrls []string) (float64, error) {
   300		// call s.getMetricValueFromURL() for each endpointsUrls in parallel goroutines (maximum 5 at a time) and sum them up
   301		const maxGoroutines = 5
   302		var mu sync.Mutex
   303		sem := semaphore.NewWeighted(maxGoroutines)
   304		expectedNbMetrics := len(endpointsUrls)
   305		nbErrors := 0
   306		var err error
   307		var firstMetricEncountered bool
   308		var aggregation float64
   309		s.logger.V(1).Info(fmt.Sprintf("start iterating %d endpoint urls", len(endpointsUrls)))
   310		for _, endpointURL := range endpointsUrls {
   311			if err := sem.Acquire(ctx, 1); err != nil {
   312				s.logger.Error(err, "Failed to acquire semaphore")
   313				continue
   314			}
   315			go func(url string) {
   316				defer sem.Release(1)
   317				metric, err := s.getMetricValueFromURL(ctx, &endpointURL)
   318	
   319				if err != nil {
   320					s.logger.V(1).Info(fmt.Sprintf("Error fetching metric for %s: %v\n", url, err))
   321					// we will ignore metric for computing aggregation when encountering error : decrease expectedNbMetrics
   322					mu.Lock()
   323					expectedNbMetrics--
   324					nbErrors++
   325					mu.Unlock()
   326				} else {
   327					mu.Lock()
   328					switch s.metadata.AggregationType {
   329					case MinAggregationType:
   330						if !firstMetricEncountered || metric < aggregation {
   331							firstMetricEncountered = true
   332							aggregation = metric
   333						}
   334					case MaxAggregationType:
   335						if !firstMetricEncountered || metric > aggregation {
   336							firstMetricEncountered = true
   337							aggregation = metric
   338						}
   339					default:
   340						// sum metrics if we are not looking for min or max value
   341						aggregation += metric
   342					}
   343					mu.Unlock()
   344				}
   345			}(endpointURL)
   346		}
   347		// Wait that all goroutines have released their semaphore acquisition
   348		if err := sem.Acquire(ctx, maxGoroutines); err != nil {
   349			s.logger.V(1).Error(err, "final semaphore acquisition failed")
   350		}
   351		s.logger.V(1).Info(fmt.Sprintf("ENDED iterating %d endpoint urls, aggregation is now %v", len(endpointsUrls), aggregation))
   352	
   353		if nbErrors > 0 && nbErrors == len(endpointsUrls) {
   354			err = fmt.Errorf("could not get any metric successfully from the %d provided endpoints", len(endpointsUrls))
   355		}
   356		if s.metadata.AggregationType == AverageAggregationType {
   357			aggregation /= float64(expectedNbMetrics)
   358		}
   359		s.logger.V(1).Info(fmt.Sprintf("fetched %d metrics out of %d endpoints from kubernetes service : %s is %v\n", expectedNbMetrics, len(endpointsUrls), s.metadata.AggregationType, aggregation))
   360		return aggregation, err
   361	}
