   363	func (s *metricsAPIScaler) getMetricValueFromURL(ctx context.Context, url *string) (float64, error) {
   364		request, err := getMetricAPIServerRequest(ctx, s.metadata, url)
   365		if err != nil {
   366			return 0, err
   367		}
   368	
   369		r, err := s.httpClient.Do(request)
   370		if err != nil {
   371			return 0, err
   372		}
   373		defer r.Body.Close()
   374	
   375		if r.StatusCode != http.StatusOK {
   376			msg := fmt.Sprintf("%s: api returned %d", r.Request.URL.Path, r.StatusCode)
   377			return 0, errors.New(msg)
   378		}
   379	
   380		b, err := io.ReadAll(r.Body)
   381		if err != nil {
   382			return 0, err
   383		}
   384		v, err := GetValueFromResponse(b, s.metadata.ValueLocation, s.metadata.Format)
   385		if err != nil {
   386			return 0, err
   387		}
   388		return v, nil
   389	}
