   400	func (s *metricsAPIScaler) GetMetricSpecForScaling(context.Context) []v2.MetricSpec {
   401		externalMetric := &v2.ExternalMetricSource{
   402			Metric: v2.MetricIdentifier{
   403				Name: GenerateMetricNameWithIndex(s.metadata.triggerIndex, kedautil.NormalizeString(fmt.Sprintf("metric-api-%s", s.metadata.ValueLocation))),
   404			},
   405			Target: GetMetricTargetMili(s.metricType, s.metadata.TargetValue),
   406		}
