   413	// GetMetricsAndActivity returns value for a supported metric and an error if there is a problem getting the metric
   414	func (s *metricsAPIScaler) GetMetricsAndActivity(ctx context.Context, metricName string) ([]external_metrics.ExternalMetricValue, bool, error) {
   415		val, err := s.getMetricValue(ctx)
   416		if err != nil {
   417			return []external_metrics.ExternalMetricValue{}, false, fmt.Errorf("error requesting metrics endpoint: %w", err)
   418		}
   419	
   420		metric := GenerateMetricInMili(metricName, val)
   421	
   422		return []external_metrics.ExternalMetricValue{metric}, val > s.metadata.ActivationTargetValue, nil
   423	}
