   425	func getMetricAPIServerRequest(ctx context.Context, meta *metricsAPIScalerMetadata, url *string) (*http.Request, error) {
   426		var requestURL string
   427		if url == nil {
   428			url = &meta.URL
   429		}
   430		// Handle API Key as query parameter if needed
   431		if meta.MetricsAPIAuth != nil && meta.MetricsAPIAuth.EnabledAPIKeyAuth() && meta.MetricsAPIAuth.Method == methodValueQuery {
   432			url, _ := neturl.Parse(*url)
   433			queryString := url.Query()
   434			if meta.MetricsAPIAuth.KeyParamName == "" {
   435				queryString.Set("api_key", meta.MetricsAPIAuth.APIKey)
   436			} else {
   437				queryString.Set(meta.MetricsAPIAuth.KeyParamName, meta.MetricsAPIAuth.APIKey)
   438			}
   439			url.RawQuery = queryString.Encode()
   440			requestURL = url.String()
   441		} else {
   442			requestURL = *url
   443		}
   444	
   445		// Create the request
   446		req, err := http.NewRequestWithContext(ctx, "GET", requestURL, nil)
   447		if err != nil {
   448			return nil, err
   449		}
   450	
   451		// Add API Key as header if needed
   452		if meta.MetricsAPIAuth != nil && meta.MetricsAPIAuth.EnabledAPIKeyAuth() && meta.MetricsAPIAuth.Method != methodValueQuery {
   453			if meta.MetricsAPIAuth.KeyParamName == "" {
   454				req.Header.Add("X-API-KEY", meta.MetricsAPIAuth.APIKey)
   455			} else {
   456				req.Header.Add(meta.MetricsAPIAuth.KeyParamName, meta.MetricsAPIAuth.APIKey)
   457			}
   458		}
   459	
   460		// Add Basic Auth if enabled
   461		if meta.MetricsAPIAuth != nil && meta.MetricsAPIAuth.EnabledBasicAuth() {
   462			req.SetBasicAuth(meta.MetricsAPIAuth.Username, meta.MetricsAPIAuth.Password)
   463		}
   464	
   465		// Add Bearer token if enabled
   466		if meta.MetricsAPIAuth != nil && meta.MetricsAPIAuth.EnabledBearerAuth() {
   467			req.Header.Add("Authorization", fmt.Sprintf("Bearer %s", meta.MetricsAPIAuth.BearerToken))
   468		}
   469	
   470		return req, nil
   471	}
